import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import { formatDistanceToNow } from 'date-fns';
import { FaHeart, FaRegHeart, FaComment, FaLock, FaGlobe } from 'react-icons/fa';
import './Feed.css';

const Feed = () => {
  const [posts, setPosts] = useState([]);
  const [newPost, setNewPost] = useState({ content: '', image: null, privacy: 'public' });
  const [loading, setLoading] = useState(true);
  const [commentInputs, setCommentInputs] = useState({});
  const [replyInputs, setReplyInputs] = useState({});
  const { user, logout } = useAuth();

  useEffect(() => {
    fetchPosts();
  }, []);

  const fetchPosts = async () => {
    try {
      const response = await axios.get('http://localhost:8000/api/posts/');
      setPosts(response.data.results || response.data);
    } catch (error) {
      console.error('Error fetching posts:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleCreatePost = async (e) => {
    e.preventDefault();
    const formData = new FormData();
    formData.append('content', newPost.content);
    formData.append('privacy', newPost.privacy);
    if (newPost.image) {
      formData.append('image', newPost.image);
    }

    try {
      const response = await axios.post('http://localhost:8000/api/posts/', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      setPosts([response.data, ...posts]);
      setNewPost({ content: '', image: null, privacy: 'public' });
    } catch (error) {
      console.error('Error creating post:', error);
    }
  };

  const handleLike = async (postId) => {
    try {
      await axios.post(`http://localhost:8000/api/posts/${postId}/like/`);
      fetchPosts();
    } catch (error) {
      console.error('Error liking post:', error);
    }
  };

  const handleComment = async (postId) => {
    const content = commentInputs[postId];
    if (!content?.trim()) return;

    try {
      await axios.post(`http://localhost:8000/api/posts/${postId}/comment/`, { content });
      setCommentInputs({ ...commentInputs, [postId]: '' });
      fetchPosts();
    } catch (error) {
      console.error('Error commenting:', error);
    }
  };

  const handleCommentLike = async (commentId) => {
    try {
      await axios.post(`http://localhost:8000/api/comments/${commentId}/like/`);
      fetchPosts();
    } catch (error) {
      console.error('Error liking comment:', error);
    }
  };

  const handleReply = async (commentId) => {
    const content = replyInputs[commentId];
    if (!content?.trim()) return;

    try {
      await axios.post(`http://localhost:8000/api/comments/${commentId}/reply/`, { content });
      setReplyInputs({ ...replyInputs, [commentId]: '' });
      fetchPosts();
    } catch (error) {
      console.error('Error replying:', error);
    }
  };

  const handleReplyLike = async (replyId) => {
    try {
      await axios.post(`http://localhost:8000/api/replies/${replyId}/like/`);
      fetchPosts();
    } catch (error) {
      console.error('Error liking reply:', error);
    }
  };

  if (loading) return <div className="loading">Loading...</div>;

  return (
    <div className="feed-container">
      <div className="feed-header">
        <h2>Feed</h2>
        <div className="user-info">
          <span>Welcome, {user?.first_name} {user?.last_name}</span>
          <button onClick={logout} className="logout-btn">Logout</button>
        </div>
      </div>

      <div className="create-post">
        <form onSubmit={handleCreatePost}>
          <textarea
            placeholder="What's on your mind?"
            value={newPost.content}
            onChange={(e) => setNewPost({ ...newPost, content: e.target.value })}
            required
          />
          <div className="post-options">
            <input
              type="file"
              accept="image/*"
              onChange={(e) => setNewPost({ ...newPost, image: e.target.files[0] })}
            />
            <select
              value={newPost.privacy}
              onChange={(e) => setNewPost({ ...newPost, privacy: e.target.value })}
            >
              <option value="public">Public</option>
              <option value="private">Private</option>
            </select>
            <button type="submit">Post</button>
          </div>
        </form>
      </div>

      <div className="posts-list">
        {posts.map((post) => (
          <div key={post.id} className="post-card">
            <div className="post-header">
              <div className="post-author">
                <strong>{post.author.first_name} {post.author.last_name}</strong>
                <span className="post-email">{post.author.email}</span>
              </div>
              <div className="post-privacy">
                {post.privacy === 'private' ? <FaLock /> : <FaGlobe />}
                <span>{post.privacy}</span>
              </div>
            </div>

            <div className="post-content">{post.content}</div>
            {post.image && (
              <img src={`http://localhost:8000${post.image}`} alt="Post" className="post-image" />
            )}

            <div className="post-stats">
              <span>{post.likes_count} likes</span>
              <span>{post.comments_count} comments</span>
            </div>

            <div className="post-actions">
              <button onClick={() => handleLike(post.id)}>
                {post.user_has_liked ? <FaHeart color="red" /> : <FaRegHeart />}
                Like
              </button>
              <button><FaComment /> Comment</button>
            </div>

            <div className="post-likes">
              <strong>Liked by:</strong>
              {post.likes?.slice(0, 5).map(like => (
                <span key={like.id}>{like.user.first_name}</span>
              ))}
              {post.likes_count > 5 && <span>and {post.likes_count - 5} others</span>}
            </div>

            <div className="comments-section">
              {post.comments?.map((comment) => (
                <div key={comment.id} className="comment">
                  <div className="comment-header">
                    <strong>{comment.author.first_name} {comment.author.last_name}</strong>
                    <span className="comment-time">
                      {formatDistanceToNow(new Date(comment.created_at))} ago
                    </span>
                  </div>
                  <div className="comment-content">{comment.content}</div>
                  <div className="comment-actions">
                    <button onClick={() => handleCommentLike(comment.id)}>
                      {comment.user_has_liked ? <FaHeart color="red" /> : <FaRegHeart />}
                      {comment.likes_count}
                    </button>
                    <button onClick={() => {
                      const replyInput = document.getElementById(`reply-input-${comment.id}`);
                      if (replyInput) replyInput.style.display = replyInput.style.display === 'none' ? 'block' : 'none';
                    }}>
                      Reply
                    </button>
                  </div>

                  <div className="comment-likes">
                    {comment.likes?.slice(0, 3).map(like => (
                      <span key={like.id}>{like.user.first_name}</span>
                    ))}
                  </div>

                  <div className="replies-section">
                    {comment.replies?.map((reply) => (
                      <div key={reply.id} className="reply">
                        <div className="reply-header">
                          <strong>{reply.author.first_name} {reply.author.last_name}</strong>
                          <span className="reply-time">
                            {formatDistanceToNow(new Date(reply.created_at))} ago
                          </span>
                        </div>
                        <div className="reply-content">{reply.content}</div>
                        <button onClick={() => handleReplyLike(reply.id)}>
                          {reply.user_has_liked ? <FaHeart color="red" /> : <FaRegHeart />}
                          {reply.likes_count}
                        </button>
                      </div>
                    ))}
                  </div>

                  <div className="reply-input" id={`reply-input-${comment.id}`} style={{ display: 'none' }}>
                    <input
                      type="text"
                      placeholder="Write a reply..."
                      value={replyInputs[comment.id] || ''}
                      onChange={(e) => setReplyInputs({ ...replyInputs, [comment.id]: e.target.value })}
                    />
                    <button onClick={() => handleReply(comment.id)}>Reply</button>
                  </div>
                </div>
              ))}

              <div className="new-comment">
                <input
                  type="text"
                  placeholder="Write a comment..."
                  value={commentInputs[post.id] || ''}
                  onChange={(e) => setCommentInputs({ ...commentInputs, [post.id]: e.target.value })}
                />
                <button onClick={() => handleComment(post.id)}>Comment</button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Feed;
